"const fs = require('fs');
const readline = require('readline');

const logPath = 'C:/Users/paloptical/.gemini/antigravity/brain/f89774ed-f905-432d-8902-e9fb55f69e45/.system_generated/logs/transcript.jsonl';

const rl = readline.createInterface({
  input: fs.createReadStream(logPath),
  crlfDelay: Infinity
});

let lineCount = 0;

rl.on('line', (line) => {
  lineCount++;
  if (line.includes('App.tsx') && (line.includes('write_to_file') || line.includes('replace_file_content'))) {
    try {
      const data = JSON.parse(line);
      console.log(`Line ${lineCount}: step=${data.step_index}, type=${data.type}`);
      if (data.tool_calls) {
        for (const call of data.tool_calls) {
          if (call.name === 'write_to_file' && call.args.TargetFile && call.args.TargetFile.includes('App.tsx')) {
            console.log(`  write_to_file target: ${call.args.TargetFile}`);
            console.log(`  Code length: ${call.args.CodeContent ? call.args.CodeContent.length : 'undefined'}`);
            if (call.args.CodeContent) {
              fs.writeFileSync(`app_tsx_write_${data.step_index}.txt`, call.args.CodeContent);
              console.log(`  Saved CodeContent to app_tsx_write_${data.step_index}.txt`);
            }
          }
          if (call.name === 'replace_file_content' && call.args.TargetFile && call.args.TargetFile.includes('App.tsx')) {
            console.log(`  replace_file_content target: ${call.args.TargetFile}`);
            console.log(`  Instruction: ${call.args.Instruction}`);
          }
        }
      }
    } catch (e) {
      // Ignore
    }
  }
});

rl.on('close', () => {
  console.log('Done searching write calls.');
});
"
